  4	import { useKialiTranslation } from '../../utils/I18nUtils';
  5	import { ExternalServiceInfo, TempoUrlFormat } from '../../types/StatusState';
  6	import { isParentKiosk } from '../Kiosk/KioskActions';
  7	import { isTempoService, TempoUrlProvider } from '../../utils/tracing/UrlProviders/Tempo';
  8	import { isJaegerService, JaegerUrlProvider } from '../../utils/tracing/UrlProviders/Jaeger';
  9	import { KialiAppState } from '../../store/Store';
 10	import { KialiDispatch } from '../../types/Redux';
 11	import { bindActionCreators } from 'redux';
 12	import { TracingActions } from '../../actions/TracingActions';
 13	import { connect } from 'react-redux';
 14	import { ParameterizedTabs } from '../Tab/Tabs';
 15	import { DiscoveryTracingConfig } from './DiscoveryTracingConfig';
 16	import { CheckerTracingConfig } from './CheckerTracingConfig';
 17	import { HelpIcon } from '@patternfly/react-icons';
 18	import { helpPopover } from '../../pages/Mesh/target/TargetPanelControlPlane';
 19	
 20	type ReduxProps = {
 21	  externalServices: ExternalServiceInfo[];
 22	  kiosk: string;
 23	  tracingCheck?: TracingCheck;
 24	  tracingInfo?: TracingInfo;
 25	};
 26	
 27	type ReduxDispatchProps = {
 28	  setTracingDiagnose: (err?: TracingCheck) => void;
 29	};
 30	
 31	type TraceConfigurationModalProps = ReduxProps &
 32	  ReduxDispatchProps & {
 33	    cluster: string;
 34	    configData: unknown;
 35	    isOpen: boolean;
 36	    onClose: () => void;
 37	  };
 38	
 39	const defaultTab = 'checkConfig';
 40	
 41	const tabIndex: { [tab: string]: number } = {
 42	  checkConfig: 0,
 43	  testConfig: 1
 44	};
 45	
 46	export const validateExternalUrl = (
 47	  externalServices: ExternalServiceInfo[],
 48	  kiosk: string,
 49	  info?: TracingInfo
 50	): string | undefined => {
 51	  const svc = externalServices.find(s => s.name === info?.provider);
 52	  if (!svc) return `"View in Tracing" link is hidden because external_url is not defined (No service found)`;
 53	
 54	  if (isParentKiosk(kiosk)) {
 55	    return 'kiosk mode detected. kiosk will try to use the Distributed Tracing UI link. In case the configuration is not found, it will use the external_url.';
 56	  }
 57	
 58	  if (isTempoService(svc)) {
 59	    if (svc.tempoConfig?.urlFormat === TempoUrlFormat.JAEGER) {
 60	      const urlProvider = new JaegerUrlProvider(svc);
 61	      if (!urlProvider.HomeUrl() || !urlProvider.valid) {
 62	        return '"View in Tracing" is hidden because external_url is empty';
 63	      }
 64	    } else if (svc.tempoConfig?.urlFormat === TempoUrlFormat.OPENSHIFT) {
 65	      const urlProvider = new TempoUrlProvider(svc, externalServices);
 66	      if (!urlProvider.HomeUrl() || !urlProvider.valid) {
 67	        return '"View in Tracing" is hidden because external_url is empty or invalid for OpenShift console';
 68	      }
 69	    } else {
 70	      const urlProvider = new TempoUrlProvider(svc, externalServices);
 71	      if (!urlProvider.HomeUrl() || !urlProvider.valid) {
 72	        return "\"View in Tracing\" link is hidden because Grafana is not enabled. To use external_url as 'View in tracing' link, tempo_config.url_format must be set to 'jaeger' or 'openshift'";
 73	      }
 74	    }
 75	  }
 76	  if (isJaegerService(svc)) {
 77	    const urlProvider = new JaegerUrlProvider(svc);
 78	    if (!urlProvider.HomeUrl() || !urlProvider.valid) {
 79	      return '"View in Tracing" is hidden because external_url is empty';
 80	    }
 81	  }
 82	
 83	  return undefined;
 84	};
 85	
 86	export const TraceConfigurationModalComp: React.FC<TraceConfigurationModalProps> = (
 87	  props: TraceConfigurationModalProps
 88	) => {
 89	  const { t } = useKialiTranslation();
 90	
 91	  const [currentTab, setCurrentTab] = React.useState(defaultTab);
 92	
 93	  const checkConfigHelp = (
 94	    <>
 95	      {t(
 96	        'Check the usual ports for the tracing service and provide a subset of the tracing configuration based on the tracing services found for external_services.tracing.'
 97	      )}
 98	      <br />
 99	      {t(
100	        'While the health check is simple and checks only for an HTTP 200 response for the URL, this check is more comprehensive and attempts to validate the returned trace data. It will typically use the internal_url to perform the checks. If Kiali is running outside of the cluster, the external_url will be used.'
101	      )}
102	    </>
103	  );
104	
105	  const testConfigHelp = (
106	    <>
107	      {t('Edit and test configuration changes without having to modify the CR.')}
108	      <br />
109	      {t(
110	        'Changes here are not saved to the Kiali CR. If happy with changes, update the Kiali CR using your standard change workflow.'
111	      )}
112	    </>
113	  );
114	
115	  const renderTabs = (): React.ReactNode[] => {
116	    const ref = React.createRef<HTMLElement>();
117	    const refTest = React.createRef<HTMLElement>();
118	    const checkConfig = (
119	      <Tab
120	        eventKey={0}
121	        title={t('Discovery')}
122	        key="checkConfig"
123	        actions={
124	          <>
125	            <TabAction aria-label={`Help action for Check config`} ref={ref}>
126	              <HelpIcon />
127	            </TabAction>
128	            {helpPopover(t('Configuration Discovery'), checkConfigHelp, ref)}
129	          </>
130	        }
131	      >
132	        <DiscoveryTracingConfig cluster={props.cluster} />
133	      </Tab>
134	    );
135	
136	    const testConfig = (
137	      <Tab
138	        eventKey={1}
139	        title={t('Tester')}
140	        key="testConfig"
141	        actions={
142	          <>
143	            <TabAction aria-label={`Help action for configuration test`} ref={refTest}>
144	              <HelpIcon />
145	            </TabAction>
146	            {helpPopover(t('Configuration Tester'), testConfigHelp, refTest)}
147	          </>
148	        }
149	      >
150	        <CheckerTracingConfig configData={props.configData} />
151	      </Tab>
152	    );
153	
154	    return [checkConfig, testConfig];
155	  };
156	
157	  if (!props.isOpen) {
158	    return null;
159	  }
160	
161	  return (
162	    <Modal
163	      variant={ModalVariant.medium}
164	      isOpen={props.isOpen}
165	      onClose={props.onClose}
166	      data-test="modal-configuration-tester"
167	      title={t('Configuration Tester')}
168	      actions={[
169	        <Button key="close" onClick={props.onClose}>
170	          {t('Close')}
171	        </Button>
172	      ]}
173	    >
174	      <ParameterizedTabs
175	        id="basic-tabs"
176	        onSelect={tabValue => {
177	          setCurrentTab(tabValue);
178	        }}
179	        tabMap={tabIndex}
180	        defaultTab={defaultTab}
181	        activeTab={currentTab}
182	        mountOnEnter={false}
183	        unmountOnExit={false}
184	      >
185	        {renderTabs()}
186	      </ParameterizedTabs>
187	    </Modal>
188	  );
189	};
190	
191	const mapStateToProps = (state: KialiAppState): ReduxProps => {
192	  return {
193	    externalServices: state.statusState.externalServices,
194	    kiosk: state.globalState.kiosk,
195	    tracingCheck: state.tracingState.diagnose,
196	    tracingInfo: state.tracingState.info
197	  };
198	};
199	
200	const mapDispatchToProps = (dispatch: KialiDispatch): ReduxDispatchProps => ({
201	  setTracingDiagnose: bindActionCreators(TracingActions.setDiagnose, dispatch)
202	});
203	
204	export const TraceConfigurationModal = connect(mapStateToProps, mapDispatchToProps)(TraceConfigurationModalComp);

